     1	using Riok.Mapperly.Abstractions;
     2	using Riok.Mapperly.Configuration.PropertyReferences;
     3	using Riok.Mapperly.Helpers;
     4	
     5	namespace Riok.Mapperly.Descriptors;
     6	
     7	public static class MemberPathCandidateBuilder
     8	{
     9	    /// <summary>
    10	    /// Maximum number of indices which are considered to compute the member path candidates.
    11	    /// </summary>
    12	    private const int MaxPermutationIndices = 8;
    13	
    14	    /// <summary>
    15	    /// Splits a name into chunks and joins them together in all possible combinations.
    16	    /// <example><c>"MyValueId"</c> leads to <c>[["MyValueId"], ["My", "ValueId"], ["MyValue", "Id"], ["My", "Value", "Id"]</c></example>
    17	    /// </summary>
    18	    /// <param name="name">The name to build candidates from.</param>
    19	    /// <param name="strategy">The naming strategy to use.</param>
    20	    /// <returns>The joined member path groups.</returns>
    21	    public static IEnumerable<StringMemberPath> BuildMemberPathCandidates(string name, PropertyNameMappingStrategy strategy)
    22	    {
    23	        if (string.IsNullOrEmpty(name))
    24	            return [];
    25	
    26	        return BuildCandidates(name, strategy).Prepend(new StringMemberPath([name])).DistinctBy(x => x.FullName);
    27	    }
    28	
    29	    private static IEnumerable<StringMemberPath> BuildCandidates(string name, PropertyNameMappingStrategy strategy)
    30	    {
    31	        return strategy switch
    32	        {
    33	            PropertyNameMappingStrategy.SnakeCase => BuildSnakeCaseCandidates(name, name.ToSnakeCase()),
    34	            PropertyNameMappingStrategy.UpperSnakeCase => BuildSnakeCaseCandidates(name, name.ToUpperSnakeCase()),
    35	            _ => BuildPermutations(name, char.IsUpper, skipSeparator: false),
    36	        };
    37	    }
    38	
    39	    private static IEnumerable<StringMemberPath> BuildSnakeCaseCandidates(string originalName, string snakeCaseName)
    40	    {
    41	        var snakeCasePermutations = BuildPermutations(snakeCaseName, static c => c == '_', skipSeparator: true);
    42	
    43	        // PascalCase Fallback
    44	        var pascalCaseSource = originalName.Contains('_', StringComparison.Ordinal) ? originalName.ToPascalCase() : originalName;
    45	        var pascalCasePermutations = BuildCandidates(pascalCaseSource, PropertyNameMappingStrategy.CaseSensitive);
    46	        return snakeCasePermutations.Concat(pascalCasePermutations);
    47	    }
    48	
    49	    private static IEnumerable<StringMemberPath> BuildPermutations(string name, Func<char, bool> isSeparator, bool skipSeparator)
    50	    {
    51	        var indices = GetSplitIndices(name, isSeparator).Take(MaxPermutationIndices).ToArray();
    52	
    53	        // try all permutations
    54	        var permutationsCount = 1 << indices.Length;
    55	        for (var i = 0; i < permutationsCount; i++)
    56	        {
    57	            yield return new StringMemberPath(BuildPermutationParts(name, indices, i, skipSeparator));
    58	        }
    59	    }
    60	
    61	    private static IEnumerable<string> BuildPermutationParts(
    62	        string source,
    63	        int[] splitIndices,
    64	        int enabledSplitPositions,
    65	        bool skipSplitIndex
    66	    )
    67	    {
    68	        var lastSplitIndex = 0;
    69	        var currentSplitPosition = 1;
    70	        foreach (var splitIndex in splitIndices)
    71	        {
    72	            if ((enabledSplitPositions & currentSplitPosition) == currentSplitPosition)
    73	            {
    74	                yield return source.Substring(lastSplitIndex, splitIndex - lastSplitIndex);
    75	                lastSplitIndex = splitIndex + (skipSplitIndex ? 1 : 0);
    76	            }
    77	
    78	            currentSplitPosition <<= 1;
    79	        }
    80	
    81	        if (lastSplitIndex < source.Length)
    82	            yield return source.Substring(lastSplitIndex);
    83	    }
    84	
    85	    private static IEnumerable<int> GetSplitIndices(string str, Func<char, bool> isSeparator)
    86	    {
    87	        for (var i = 1; i < str.Length; i++)
    88	        {
    89	            if (isSeparator(str[i]))
    90	                yield return i;
    91	        }
    92	    }
    93	}
