   156	        // iterate backwards, if a reference type property is found then path is valid
   157	        // if a value type property is found then invalid, a temporary struct is being modified
   158	        for (var i = memberInfo.TargetMember.Path.Count - 2; i >= 0; i--)
   159	        {
   160	            var member = memberInfo.TargetMember.Path[i];
   161	            if (member is PropertyMember { Type: { IsValueType: true, IsRefLikeType: false } })
   162	            {
   163	                ctx.BuilderContext.ReportDiagnostic(
   164	                    DiagnosticDescriptors.CannotMapToTemporarySourceMember,
   165	                    memberInfo.DescribeSource(),
   166	                    memberInfo.TargetMember.ToDisplayString(),
   167	                    member.Type,
   168	                    member.Name
   169	                );
   170	                return false;
   171	            }
   172	
   173	            if (member is PropertyMember { Type.IsReferenceType: true })
   174	                break;
   175	        }
   176	
   177	        return true;
   178	    }
