   178	    private static IEnumerable<MethodDeclarationSyntax> ExtractAllMethods(SyntaxNode? root)
   179	    {
   180	        if (root == null)
   181	            yield break;
   182	
   183	        foreach (var node in root.ChildNodes())
   184	        {
   185	            // a namespace can contain classes
   186	            if (node is NamespaceDeclarationSyntax)
   187	            {
   188	                foreach (var method in ExtractAllMethods(node))
   189	                {
   190	                    yield return method;
   191	                }
   192	            }
   193	
   194	            // a class can contain methods or other classes
   195	            if (node is not ClassDeclarationSyntax classNode)
   196	                continue;
   197	
   198	            foreach (var method in classNode.ChildNodes().OfType<MethodDeclarationSyntax>())
   199	            {
   200	                yield return method;
   201	            }
   202	
   203	            foreach (var method in ExtractAllMethods(node))
   204	            {
   205	                yield return method;
   206	            }
   207	        }
   208	    }
